#!/usr/bin/env python3

class Solution:

    def generate_bit_masks(self, n: int, nums: list[int]) -> list[int]:

        result = []

        for i in range(n):

            bits = nums[i]

            next_value = bits

            while bits != 0:

                next_value = bits << 1

                if (next_value & bits) != 0:

                    result.append(next_value | bits)

                    break

                bits = next_value 

        return result

