#include <iostream>

#include <vector>

using namespace std;

class Solution {

public:

    vector<int> generateBitMasks(int n, vector<int>& nums) {

        vector<int> result;

        for (int i = 0; i < n; i++) {

            int bits = nums[i];

            int next_value = bits;

            while (bits != 0) {

                next_value = bits << 1;

                if ((next_value & bits) != 0) {

                    result.push_back(next_value | bits);

                    break;

                }

                bits = next_value;

            }

        }

        return result;

    }

};

